request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?prop ?val WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:originalId ?oid .
    FILTER(CONTAINS(LCASE(STR(?oid)), "2d225c9ff86b443c9f6bc6cfe687afbc"))
  }
  UNION
  {
    ?model tai:normalizedId ?nid .
    FILTER(CONTAINS(LCASE(STR(?nid)), "2d225c9ff86b443c9f6bc6cfe687afbc"))
  }
  UNION
  {
    FILTER(CONTAINS(STR(?model), "2d225c9ff86b443c9f6bc6cfe687afbc"))
  }
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model ?prop ?val .
}
LIMIT 25
